import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './Footer.css';

const Footer = () => {
  const [email, setEmail] = useState('');
  const [newsletterStatus, setNewsletterStatus] = useState({ type: '', message: '' });

  const handleNewsletterSubmit = (e) => {
    e.preventDefault();
    // In a real app, this would submit to an API
    setNewsletterStatus({ type: 'success', message: 'Thank you! Your submission has been received!' });
    setEmail('');
    setTimeout(() => setNewsletterStatus({ type: '', message: '' }), 5000);
  };

  return (
    <footer className="footer">
      <div className="container">
        <div className="footer-content">
          <div className="footer-section">
            <h3>Greyline Accountants Ltd.</h3>
            <p>Professional accounting and tax services for businesses of all sizes.</p>
          </div>

          <div className="footer-section">
            <h4>Quick links</h4>
            <ul>
              <li><Link to="/services">Services</Link></li>
              <li><Link to="/blog">Insights</Link></li>
              <li><Link to="/about">About</Link></li>
              <li><Link to="/contact">Contact</Link></li>
            </ul>
          </div>

          <div className="footer-section">
            <h4>Get in touch</h4>
            <ul>
              <li>hello@greylineaccountants.co.uk</li>
              <li>+44 (0) 20 1234 5678</li>
            </ul>
          </div>

          <div className="footer-section">
            <h4>Subscribe to our newsletter</h4>
            <p className="newsletter-text">Get agency insights straight to your inbox</p>
            <form className="newsletter-form" onSubmit={handleNewsletterSubmit}>
              <input
                type="email"
                placeholder="Your email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
              <button type="submit" className="btn-newsletter">Subscribe</button>
            </form>
            {newsletterStatus.message && (
              <div className={`newsletter-status ${newsletterStatus.type}`}>
                {newsletterStatus.message}
              </div>
            )}
            <p className="newsletter-privacy">
              By subscribing you agree with our Privacy Policy and provide consent to receive updates from our company.
            </p>
          </div>
        </div>

        <div className="footer-bottom">
          <p>&copy; {new Date().getFullYear()} Greyline Accountants Ltd. All rights reserved.</p>
          <div className="footer-links">
            <Link to="/privacy">Privacy</Link>
            <Link to="/terms">Terms</Link>
            <Link to="/cookies">Cookies</Link>
          </div>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
